query:
UPDATE v2Stages SET stageName='金乌羽扇', weaponEmoji='☀️', storyBefore='须弥世界的顶端，金乌展翅，光芒万丈。「金乌海底初飞来，朱辉照耀喧风雷。」——韩愈《石鼓歌》中的金乌化为一把羽扇，扇动时能召唤日月之力，驱散一切黑暗。', storyAfter='金乌羽扇一挥，须弥世界的黑暗被彻底照亮。第五章须弥见方完成，你已将万千世界收纳于心。' WHERE stageNumber=15;
UPDATE v2Stages SET stageName='精卫神石', weaponEmoji='🪨', storyBefore='重回人间，繁华与乱世交织。「常衔山木来，以堙沧海波。」——精卫填海的坚韧化为一块神石，它承载着千年的执念与不屈。只有同样坚韧的人，才能驾驭这股力量。', storyAfter='精卫神石在手，沧海波涛被一点点填平。你的坚韧与执着，正是破除毒龙封印的关键所在。' WHERE stageNumber=16;
UPDATE v2Stages SET stageName='气蒸水戟', weaponEmoji='🌊', storyBefore='洞庭湖畔，云梦泽上，水汽蒸腾如龙。「气蒸云梦泽，波撼岳阳城。」——孟浩然《望洞庭湖赠张丞相》中的磅礴气势化为一把水戟，能以水克火，破除毒龙的火焰封印。', storyAfter='气蒸水戟刺出，云梦泽的水气将毒龙的火焰一一扑灭。浮世清响章节进入最后阶段。' WHERE stageNumber=17;
UPDATE v2Stages SET stageName='琵琶金索', weaponEmoji='🎵', storyBefore='丝竹石阵之中，琵琶声如泣如诉。「大弦嘈嘈如急雨，小弦切切如私语。」——白居易《琵琶行》中的音律化为一条金索，能以音波震碎石阵，为樊登打开一条通道。', storyAfter='琵琶金索奏响，石阵在音波中轰然崩塌。第六章浮世清响完成，人间的繁华与乱世已被你看透。' WHERE stageNumber=18;
UPDATE v2Stages SET stageName='八阵石符', weaponEmoji='🔯', storyBefore='终极决战的前夕，杜甫的八阵图出现在你面前。「功盖三分国，名成八阵图。」——这八块石符是诸葛亮留下的战阵遗产，也是对抗毒龙的终极武器之一。', storyAfter='八阵石符激活，战阵之力护佑四方。毒龙的封印出现了第一道裂缝，决战即将到来。' WHERE stageNumber=19;
UPDATE v2Stages SET stageName='曼陀罗轮', weaponEmoji='🌀', storyBefore='毒龙的巢穴中，密教法器散落一地。「法轮常转，扫荡群魔。」——晚唐密教的力量在此汇聚，化为一个旋转不息的曼陀罗轮，能以无上法力震慑毒龙。', storyAfter='曼陀罗轮高速旋转，毒龙的封印出现了第二道裂缝。最终的决战时刻即将到来！' WHERE stageNumber=20;
UPDATE v2Stages SET stageName='安禅法印', weaponEmoji='☯️', storyBefore='最终决战。毒龙盘踞于空潭之上，封印着讲书人樊登。「薄暮空潭曲，安禅制毒龙。」——王维《过香积寺》中的禅意化为最终的法印。以无上禅心，降服毒龙，解救樊登！', storyAfter='安禅法印落下，毒龙在禅意中化为虚无。封印彻底破除，樊登重获自由！「感谢你，以诗词之力，完成了这场跨越时空的解救。」第七章万重归一，圆满完成！' WHERE stageNumber=21;

